253	          resolve: (result) => resolve(mapResult(result)),
254	          reject,
255	        }
256	
257	        this.sendMessage(
258	          {
259	            jsonrpc: '2.0',
260	            method,
261	            params,
262	            id: messageId,
263	          },
264	          (error) => {
