import type { DMMF } from '@prisma/dmmf'

import { renderEnum, renderFileHeader, renderModelInterface, renderModelMethods } from './template'

/**
 * Generates the full content of `rest-client.ts` from the provided DMMF document.
 *
 * The output contains:
 * - A file header warning not to edit the file manually
 * - One `enum` block per Prisma enum
 * - One `interface` block per Prisma model (scalar and enum fields only)
 * - A `RestClient` class whose methods cover the five basic CRUD operations
 *   (`findMany`, `findUnique`, `create`, `update`, `delete`) for every model
 */
export function generateRestClient(dmmf: DMMF.Document): string {
  const parts: string[] = [renderFileHeader()]

  for (const enumDef of dmmf.datamodel.enums) {
    parts.push(renderEnum(enumDef))
  }

  for (const model of dmmf.datamodel.models) {
    parts.push(renderModelInterface(model))
  }

  parts.push(renderRestClientClass(dmmf.datamodel.models))

  return parts.join('\n\n') + '\n'
}

function renderRestClientClass(models: readonly DMMF.Model[]): string {
  const methodBlocks = models.map(renderModelMethods)
  return [
    `export class RestClient {`,
    `  constructor(private readonly baseUrl: string) {}`,
    ``,
    methodBlocks.join('\n\n'),
    `}`,
  ].join('\n')
}

